#include <vector>
#include <algorithm>
#include <iostream>

int main() {
    std::vector<int> nums = {5, 2, 8, 1, 9, 3};
    int threshold = 4;

    // Lambda capturing threshold by value
    auto isAbove = [threshold](int n) { return n > threshold; };

    // Use with algorithm
    std::sort(nums.begin(), nums.end());
    auto it = std::find_if(nums.begin(), nums.end(), isAbove);
    std::cout << "First above " << threshold << ": " << *it << '\n';

    // Mutable lambda
    int count = 0;
    auto counter = [count](int) mutable { return ++count; }; // count is copy

    // Generic lambda (C++14)
    auto printAny = [](auto val) { std::cout << val << '\n'; };
    printAny(42);
    printAny("hello");
}

#include <utility>
#include <cstring>

class Buffer {
public:
    explicit Buffer(std::size_t size)
        : data_(new char[size]), size_(size) {}

    ~Buffer() { delete[] data_; }               // 1. Destructor

    Buffer(const Buffer& other)                  // 2. Copy constructor
        : data_(new char[other.size_]), size_(other.size_) {
        std::memcpy(data_, other.data_, size_);
    }

    Buffer& operator=(const Buffer& other) {     // 3. Copy assignment
        if (this != &other) {                    //    Self-assignment check
            Buffer tmp(other);                   //    Copy-and-swap idiom
            swap(tmp);
        }
        return *this;
    }

    Buffer(Buffer&& other) noexcept              // 4. Move constructor
        : data_(other.data_), size_(other.size_) {
        other.data_ = nullptr; other.size_ = 0;
    }

    Buffer& operator=(Buffer&& other) noexcept { // 5. Move assignment
        if (this != &other) { Buffer tmp(std::move(other)); swap(tmp); }
        return *this;
    }

private:
    void swap(Buffer& other) noexcept {
        std::swap(data_, other.data_);
        std::swap(size_, other.size_);
    }
    char* data_;
    std::size_t size_;
};

#include <iostream>
#include <memory>
#include <vector>

class Shape {
public:
    virtual double area() const = 0;          // Pure virtual
    virtual void describe() const {           // Virtual with default
        std::cout << "Shape\n";
    }
    virtual ~Shape() = default;               // Virtual destructor
};

class Circle : public Shape {
public:
    explicit Circle(double r) : radius_(r) {}
    double area() const override {            // override keyword
        return 3.14159 * radius_ * radius_;
    }
    void describe() const override final {
        std::cout << "Circle r=" << radius_ << '\n';
    }
private:
    double radius_;
};

int main() {
    std::vector<std::unique_ptr<Shape>> shapes;
    shapes.push_back(std::make_unique<Circle>(5.0));
    for (const auto& s : shapes) {
        s->describe();                        // Dynamic dispatch
        std::cout << "Area: " << s->area() << '\n';
    }
}

